public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Check if the input length exceeds the buffer size
        if (userInput.length() > 10) {
            System.out.println("Input size exceeds buffer limit. Please enter a shorter string.");
            return;
        }

        // Use a safe method to copy the input into a byte array
